const ProblemsService = require("../services/ProblemsService");

async function getProblemDetail(req, res) {
  const problemId = req.params.problemId;
  try {
    const problemDetail = await ProblemsService.getProblemDetail(problemId);
    res.json(problemDetail);
  } catch (err) {
    if (err.status === 404) {
      res.status(404).json({ error: err.message });
    } else {
      res.status(500).json({ error: "Internal Server Error" });
    }
  }
}

module.exports = {
  getProblemDetail
};
